+  private async parseConfig(ctx: ParseContext): Promise<void> {
+    const config = this.settings.config;
+    this.props.configPath = undefined;
+    this.props.configValues = {};
+    if (!config) return;
+
+    const paths = config.searchPaths?.length
+      ? config.searchPaths
+      : [getCurrentDirectory()];
+    const files: Array<{ path: string; format: string }> = [];
+    for (const searchPath of paths) {
+      for (const format of config.formats ?? [".json", ".rc"]) {
+        const path = join(
+          searchPath,
+          format === ".rc" ? `.${config.name}rc` : `${config.name}${format}`,
+        );
+        if (await configFileExists(path)) {
+          files.push({ path, format });
+          break;
+        }
+      }
+      if (files.length && !config.mergeConfigs) break;
+    }
+
+    const loaded: Record<string, unknown> = {};
+    // Earlier paths win when configs are merged.
+    for (const file of files.reverse()) {
+      const values = await readConfigFile(file.path, file.format, config.parser);
+      Object.assign(loaded, flattenConfig(values));
+    }
+    this.props.configPath = files[0]?.path;
+    this.props.configValues = loaded;
+
+    const options = this.getOptions(true);
+    for (const [key, value] of Object.entries(loaded)) {
+      const option = options.find((option) => option.name === key);
+      if (!option) continue;
+      ctx.env[key] = this.parseConfigValue(key, value, option);
+    }
+  }
+
+  private parseConfigValue(key: string, value: unknown, option: Option): unknown {
+    try {
+      if (!option.args.length) {
