+        name: key,
+        value: String(input),
+      });
+      const parsed = Array.isArray(value)
+        ? value.map(parse)
+        : parse(value);
+      return option.value ? option.value(parsed) : parsed;
+    } catch (error) {
+      throw new ConfigValidationError(key, error);
+    }
