+function camelCaseConfigKey(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+  output: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = prefix
+      ? `${prefix}.${camelCaseConfigKey(rawKey)}`
+      : camelCaseConfigKey(rawKey);
+    if (item && typeof item === "object" && !Array.isArray(item)) {
+      flattenConfig(item as Record<string, unknown>, key, output);
+    } else {
+      output[key] = item;
+    }
+  }
+  return output;
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const match = /^([^=\\s]+)\\s*=\\s*(.*)$/.exec(trimmed);
+    if (!match) throw new Error("Invalid RC entry");
+    let value = match[2].trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error("Unterminated quoted RC value");
+      }
+      value = value.slice(1, -1);
+    }
+    values[match[1]] = value === "true"
+      ? true
+      : value === "false"
+      ? false
+      : /^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)
+      ? Number(value)
+      : value;
+  }
+  return values;
+}
+
+async function readConfigFile(
+  path: string,
+  format: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Promise<Record<string, unknown>> {
+  try {
+    const content = await readConfigText(path);
+    const values = parser
+      ? parser(content)
+      : format === ".json"
+      ? JSON.parse(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!values || typeof values !== "object" || Array.isArray(values)) {
+      throw new TypeError("Config must contain an object");
+    }
+    return values;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
